## Minimal runnable pseudocode (SDK embedding + events + usage + cancel + resume-by-id)

```ts
import { getModel } from "@mariozechner/pi-ai";
import {
  AuthStorage,
  ModelRegistry,
  SessionManager,
  createAgentSession,
} from "@mariozechner/pi-coding-agent";

const cwd = process.cwd();
const auth = AuthStorage.create();
const registry = new ModelRegistry(auth);

// ---- Resume by session id (lookup id -> path -> open)
const targetSessionId = process.argv[2]; // e.g. "3f8c2e1a-..."
let sessionManager = SessionManager.inMemory(cwd);

if (targetSessionId) {
  const sessions = await SessionManager.list(cwd);
  const match = sessions.find(s => s.id.startsWith(targetSessionId)); // partial UUID supported in CLI UX
  if (!match) throw new Error(`No session found for id: ${targetSessionId}`);
  sessionManager = SessionManager.open(match.path);
}

const model = getModel("anthropic", "claude-sonnet-4-20250514");
if (!model) throw new Error("Model not found");

const { session } = await createAgentSession({
  sessionManager,
  authStorage: auth,
  modelRegistry: registry,
  model,
});

session.subscribe((event) => {
  if (event.type === "message_update" && event.assistantMessageEvent.type === "text_delta") {
    process.stdout.write(event.assistantMessageEvent.delta);
  }
  if (event.type === "tool_execution_start") {
    console.log(`\n[tool start] ${event.toolName}`);
  }
  if (event.type === "tool_execution_end") {
    console.log(`\n[tool end] ${event.toolName} error=${event.isError}`);
  }
});

// Kick off a run
const run = session.prompt("Scan this repo and summarize key modules.");

// Optional cancel example
setTimeout(() => {
  void session.abort(); // cancels current run
}, 5000);

await run;

// Capture usage/cost from final assistant message
const lastAssistant = [...session.messages].reverse().find(m => m.role === "assistant");
if (lastAssistant?.role === "assistant") {
  console.log("\nusage:", lastAssistant.usage);
  console.log("cost total:", lastAssistant.usage.cost.total);
}

// Aggregate session stats (tokens/cost)
console.log("session stats:", session.getSessionStats());
```

